template <typename T>
void split(T data[], unsigned int n, T x, unsigned int& i, unsigned int& j)
{
  do {
    while (data[i] < x) i++;
    while (x < data[j]) j--;

    if (i <= j) {
      T ii = data[i];
      data[i] = data[j];
      data[j] = ii;
      i++; j--;
    }
  } while (i <= j);
}

// C.A.R. Hoare's Quick Median
template <typename T>
unsigned int quick_median(T data[], unsigned int n)
{
  unsigned int l = 0, r = n-1, k = n/2;
  while (l < r) {
    T x = data[k];
    unsigned int i = l, j = r;
    split(data, n, x, i, j);
    if (j < k) l = i;
    if (k < i) r = j;
  }
  return k;
}

