void SerialConsole::on_idle(void * argument)
{
    if(query_flag) {
        query_flag = false;
        puts(THEKERNEL->get_query_string().c_str());
    }
    if(halt_flag) {
        halt_flag = false;
        THEKERNEL->call_event(ON_HALT, nullptr);
        char c;
        while(this->buffer.get(c)) ; // flush the recieve buffer, hopefully upstream has stopped sending
        lf_count= 0;

        if(THEKERNEL->is_grbl_mode()) {
            puts("ALARM: Abort during cycle\r\n");
        } else {
            puts("HALTED, M999 or $X to exit HALT state\r\n");
        }
    }
}

// file: src/modules/communication/SerialConsole.cpp
// symbol: on_main_loop
// symbol_start: 249
// chunk_lines: 249-272
// kind: function
// class: SerialConsole
void SerialConsole::on_main_loop(void * argument)
{
    if(lf_count > 0) {
        string received;
        received.reserve(20);
        while(1) {
            char c;
            if(!this->buffer.get(c)) {
                lf_count= 0; // be safe as this should not happen anyway
                return;
            }
            if(c == '\n') {
                --lf_count;
                struct SerialMessage message;
                message.message = received;
                message.stream = this;
                THEKERNEL->call_event(ON_CONSOLE_LINE_RECEIVED, &message );
                return;
            } else {
                received += c;
            }
        }
    }
}

