void Conveyor::block_finished()
{
    if(continuous_mode <= 1){
        // we increment the isr_tail_i so we can get the next block
        queue.isr_tail_i= queue.next(queue.isr_tail_i);
        if(continuous_mode == 1) continuous_mode= 2;
    }
}

