bool Endstops::debounced_get(Pin *pin)
{
    if(pin == nullptr) return false;
    uint32_t debounce = 0;
    while(pin->get()) {
        if ( ++debounce >= this->debounce_count ) {
            // pin triggered
            return true;
        }
    }
    return false;
}

