void AnalogSpindleControl::set_speed(int rpm) 
{
    // limit the requested RPM value
    if(rpm < 0) {
        target_rpm = 0;
    } else if (rpm > max_rpm) {
        target_rpm = max_rpm;
    } else if (rpm > 0 && rpm < min_rpm){
        target_rpm = min_rpm;
    } else {
        target_rpm = rpm;
    }
    // calculate the duty cycle and update the PWM
    update_pwm(1.0f / max_rpm * target_rpm);

}

