        // Channel 1
        mosi = P0_9; miso = P0_8; sclk = P0_7;
    }

    delete spi;
    spi = new mbed::SPI(mosi, miso, sclk);

    // Spi settings: 1MHz (default), 16 bits, mode 0 (default)
    spi->format(16);
}

