void Thermistor::calc_jk()
{
    // Thermistor math
    if(beta > 0.0F) {
        j = (1.0F / beta);
        k = (1.0F / (t0 + 273.15F));
    }else{
        THEKERNEL->streams->printf("WARNING: beta cannot be 0\n");
        this->bad_config= true;
    }
}

