bool Thermistor::get_optional(sensor_options_t& options) {
    if(thermistor_number != 0) {
        options['P']= thermistor_number;
        return true;
    }

    if(use_steinhart_hart) {
        options['I']= this->c1;
        options['J']= this->c2;
        options['K']= this->c3;

    }else{
        options['B']= this->beta;
        options['X']= this->t0;
        options['R']= this->r0;
    }

    return true;
};

