void Button::check_signal(int val)
{
    bool start_value = this->value;
    if ( val ) {
        if ( this->counter < 5  ) {
            this->counter++;
        }
        if ( this->counter == 5 ) {
            this->value = true;
        }
    } else {
        if ( this->counter > 0  ) {
            this->counter--;
        }
        if ( this->counter == 0 ) {
            this->value = false;
        }
    }

    if ( start_value != this->value ) {
        if ( this->value ) {
            if ( this->up_hook != NULL ) {
                this->up_hook->call();
                this->first_timer = 0;
                this->second_timer = 0;
                this->repeat = false;
            }
        } else {
            if ( this->down_hook != NULL ) {
                this->down_hook->call();
            }
        }
    }
    //auto repeat button presses
    if(this->longpress_delay > 0) {
        if(this->value) {
            if(this->repeat) {
                this->second_timer++;
                if(this->second_timer == 10) {
                    this->up_hook->call();
                    this->second_timer = 0;
                }
            } else {
                this->first_timer++;
                if(this->first_timer == longpress_delay) {
                    this->repeat = true;
                    this->first_timer = 0;
                }
            }
        }
    }
}

