void ST7565::set_xy(int x, int y)
{
    CLAMP(x, 0, LCDWIDTH - 1);
    CLAMP(y, 0, LCDPAGES - 1);

    if(is_ssd1306) {
        unsigned char cmd[6];
        cmd[0] = 0x21;    // set column
        cmd[1] = x;       // start = col
        cmd[2] = 0x7F;    // end = col max
        cmd[3] = 0x22;    // set row
        cmd[4] = y;      // start = row
        cmd[5] = 0x07;    // end = row max
        send_commands(cmd, 6);

    }else{
        unsigned char cmd[3];
        cmd[0] = 0xb0 | (y & 0x07);
        cmd[1] = 0x10 | (x >> 4);
        cmd[2] = 0x00 | (x & 0x0f);
        send_commands(cmd, 3);
    }
}

