void ST7565::init()
{
    if(this->rst.connected()) {
        rst.set(0);
        wait_us(20);
        rst.set(1);
    }

    if(is_ssd1306) {
        const unsigned char init_seq[] = {
            0xAE,  // display off
            0xD5,  // clock
            0x81,  // upper nibble is rate, lower nibble is divisor

            0xA8,  // mux ratio
            0x3F,  // rtfm

            0xD3,  // display offset
            0x00,  // rtfm
            0x00,

            0x8D,  // charge pump
            0x14,  // enable

            0x20,  // memory addr mode
            0x00,  // horizontal

            0xA1,  // segment remap

            0xA5,  // display on

            0xC8,  // com scan direction
            0xDA,  // com hardware cfg
            0x12,  // alt com cfg

            0x81,  // contrast aka current
            0x7F,  // 128 is midpoint

            0xD9,  // precharge
            0x11,  // rtfm

            0xDB,  // vcomh deselect level
            0x20,  // rtfm

            0xA6,  // non-inverted

            0xA4,  // display scan on
            0xAF,  // drivers on
        };
        send_commands(init_seq, sizeof(init_seq));

    }else{
        const unsigned char init_seq[] = {
            0x40,    //Display start line 0
            (unsigned char)((reversed^is_sh1106) ? 0xa0 : 0xa1), // ADC
            (unsigned char)(reversed ? 0xc8 : 0xc0), // COM select
            0xa6,    //Display normal
            0xa2,    //Set Bias 1/9 (Duty 1/65)
            0x2f,    //Booster, Regulator and Follower On
            0xf8,    //Set internal Booster to 4x
            0x00,
            0x27,    //Contrast set
            0x81,
            this->contrast,    //contrast value
            0xac,    //No indicator
            0x00,
            0xaf,    //Display on
        };
        send_commands(init_seq, sizeof(init_seq));
    }

    clear();
}

