void ST7565::renderGlyph(int x, int y, const uint8_t *g, int w, int h)
{
    CLAMP(x, 0, LCDWIDTH - 1);
    CLAMP(y, 0, LCDHEIGHT - 1);
    CLAMP(w, 0, LCDWIDTH - x);
    CLAMP(h, 0, LCDHEIGHT - y);

    for(int i = 0; i < w; i++) {
        for(int j = 0; j < h; j++) {
            pixel(x + i, y + j, g[(i / 8) + j * ((w - 1) / 8 + 1)] & (1 << (7 - i % 8)));
        }
    }
}

