void ST7565::drawByte(int index, uint8_t mask, int color)
{
    int shift = (is_sh1106)? 2 : 0; // 2 pixels as border on wide OLED
    index += shift;
    if (color == 1) {
        framebuffer[index] |= mask;
    } else if (color == 0) {
        framebuffer[index] &= ~mask;
    } else {
        framebuffer[index] ^= mask;
    }
}

