void PanelScreen::send_command(const char *gcstr)
{
    string cmd(gcstr);
    while (cmd.size() > 0) {
        size_t b = cmd.find_first_of("\n");
        if ( b == string::npos ) {
            command_queue.push_back(cmd);
            break;
        }
        command_queue.push_back(cmd.substr( 0, b ));
        cmd = cmd.substr(b + 1);
    }
}

