void DirectJogScreen::tick(int change)
{
    for (int i = 0; i < multiplier; ++i) {
        if(i != 0) wait_us(100); // if you go faster than this you miss encoder changes
        THEROBOT->actuators[axis]->manual_step(change < 0);
    }
    pos_changed= true;
}

