bool FileScreen::filter_file(const char *f)
{
    string fn= lc(f);
    return (fn.at(0) != '.') &&
             ((fn.find(".g") != string::npos) ||
              (fn.find(".ngc") != string::npos) ||
              (fn.find(".nc") != string::npos));
}

